  1→#!/usr/bin/env bun
  2→
  3→/**
  4→ * Ralph Loop - Automated Claude Code Task Executor
  5→ *
  6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
  7→ * - Fresh context per iteration (new Claude instance each time)
  8→ * - Memory persists through files only (git, progress.txt)
  9→ * - One task per iteration
 10→ * - Completion signal terminates loop
 11→ *
 12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
 13→ *
 14→ * @see https://ghuntley.com/ralph/
 15→ */
 16→
 17→import { appendFileSync, mkdirSync, renameSync } from 'node:fs';
 18→import { chalk } from 'zx';
 19→
 20→const ANSI_REGEX = /\x1B\[[0-9;]*m/g;
 21→const stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');
 22→
 23→function parsePositiveInt(arg: string | undefined, fallback: number): number {
 24→  const parsed = parseInt(arg ?? String(fallback), 10);
 25→  if (isNaN(parsed) || parsed <= 0) {
 26→    console.error(`Error: expected a positive integer, got "${arg}"`);
 27→    process.exit(1);
 28→  }
 29→  return parsed;
 30→}
 31→
 32→const LOG_DIR = './.loop';
 33→mkdirSync(LOG_DIR, { recursive: true });
 34→
 35→const CONFIG = Object.freeze({
 36→  maxIterations: parsePositiveInt(Bun.argv[2], 100),
 37→  delayBetweenIterations: 1_000,
 38→  progressFile: './.claude/progress.txt',
 39→  iterationTimeout: 600_000,
 40→  logFlushInterval: 2_000,
 41→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
 42→});
 43→
 44→function slugify(text: string): string {
 45→  return text
 46→    .toLowerCase()
 47→    .normalize('NFD')
 48→    .replace(/[\u0300-\u036f]/g, '')
 49→    .replace(/[^a-z0-9]+/g, '-')
 50→    .replace(/^-+|-+$/g, '')
 51→    .slice(0, 60);
 52→}
 53→
 54→function logTimestamp(): string {
 55→  const d = new Date();
 56→  return `${d.toISOString().slice(0, 10)}_${d.toISOString().slice(11, 19).replace(/:/g, '')}`;
 57→}
 58→
 59→function logFilePath(slug: string): string {
 60→  return `${LOG_DIR}/${logTimestamp()}_${slug}.log`;
 61→}
 62→
 63→class LogBuffer {
 64→  private buf: string[] = [];
 65→  private timer: ReturnType<typeof setInterval> | null = null;
 66→  private path: string;
 67→
 68→  constructor(
 69→    initialPath: string,
 70→    private readonly flushMs: number,
 71→  ) {
 72→    this.path = initialPath;
 73→    this.timer = setInterval(() => this.flush(), this.flushMs);
 74→    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
 75→      (this.timer as NodeJS.Timeout).unref();
 76→    }
 77→  }
 78→
 79→  write(raw: string): void {
 80→    this.buf.push(stripAnsi(raw));
 81→  }
 82→
 83→  flush(): void {
 84→    if (this.buf.length === 0) return;
 85→    const chunk = this.buf.join('');
 86→    this.buf.length = 0;
 87→    try {
 88→      appendFileSync(this.path, chunk);
 89→    } catch (err) {
 90→      console.error(`[LogBuffer] write failed: ${err}`);
 91→    }
 92→  }
 93→
 94→  startNewFile(newPath: string): void {
 95→    this.flush();
 96→    this.path = newPath;
 97→  }
 98→
 99→  renameFile(newPath: string): void {
100→    this.flush();
101→    try {
102→      renameSync(this.path, newPath);
103→      this.path = newPath;
104→    } catch {}
105→  }
106→
107→  currentPath(): string {
108→    return this.path;
109→  }
110→
111→  dispose(): void {
112→    if (this.timer) clearInterval(this.timer);
113→    this.flush();
114→  }
115→}
116→
117→const logBuffer = new LogBuffer(logFilePath('startup'), CONFIG.logFlushInterval);
118→
119→type Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';
120→
121→function print(message: string, color?: Color): void {
122→  const colored = color ? chalk[color](message) : message;
123→  process.stdout.write(colored);
124→  logBuffer.write(message);
125→}
126→
127→function println(message = '', color?: Color): void {
128→  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
129→  print(`[${ts}] ${message}\n`, color);
130→}
131→
132→function syslog(message = '', color?: Color): void {
133→  println(`‣ ${message}`, color);
134→}
135→
136→const TASK_PROMPT = `
137→Read './.claude/progress.txt', 
138→pick the most important pending tasks, mark it as IN_PROGRESS immediately, 
139→execute it, update the file, commit, and stop.
140→
141→'./.claude/progress.txt' is:
142→- your persistent memory.
143→- Important errors must be registered in order to avoid expending tokens again.
144→- Never run tasks not registered in it.
145→- Register new tasks if needed, respecting the current structure.
146→
147→
148→WORKFLOW:
149→0. Understand Project
150→1. Read ./.claude/progress.txt and identify the most important pending task;
151→   - Specific task prioritization is indicated/tagged/prefixed with '[P'+number+']'
152→   - Tasks tagged with '[P0]' must be done before anything else.
153→   - Tasks tagged with P bigger than 999 (e.g. '[P1000]'), are low-priority 
154→   tasks, they should be done when possible, but they must be done 
155→   (they are not ignorable); If the task takes longer and there are other 
156→   non-low-priority tasks, document progress and revert the status to "- [ ]".
157→   
158→2. If NO pending tasks exist, signal completion (see OUTPUT STATUS below) and stop
159→3. If there are tasks, mark it as IN_PROGRESS and then sequentially run:
160→   - Evaluate scope: if the task involves more than ~3 files or multiple concerns,
161→      break it into smaller sub-tasks in progress.txt BEFORE starting. Each sub-task
162→      must be completable in a single iteration (small, atomic, committable change).
163→   - Execute task
164→   - Run 'bun run check' and fix found issues.     
165→   - Launch 1 review agents to deeply review the work, giving
166→      the entire context of the task, simulating pull request.
167→   - Review output and consider improvements
168→   - Implement corrections if needed
169→   - Update progress.txt marking task as completed
170→   - Commit task changes (not include unrelated code)
171→   - Output status block (see below)
172→   - Stop
173→  
174→OUTPUT STATUS (REQUIRED at end of EVERY response):
175→You MUST output this exact format at the END of your response:
176→
177→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
178→
179→Examples:
180→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
181→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
182→
183→CRITICAL (THINK BEFORE ACTING):
184→- ALL tasks and instructions are deliberate. 
185→- No task is optional.
186→- The FIRST thing you MUST do is write your understanding of each WORKFLOW statement
187→- The SECOND thing you MUST do is write your understanding of the work in progress described in progress.txt
188→- Only AFTER completing steps above, proceed with the task execution
189→- If more work is necessary, add a new task to the file, set "exit": false, and Stop
190→- Only set "exit": true when ALL tasks in progress.txt are completed
191→- Never remove tasks, unless to update status;
192→- Never include workarounds and add tasks to fix all you found ('as any' for example is a workaround)
193→- No task should be submitted as "look reasonable." 
194→- Every task must be delivered with professional quality, without any makeshift solutions.
195→- For tasks with visual parts, full visual and interaction tests with Playwright MCP are required.
196→- Never consider any mistake or error to be expected or acceptable.- Never consider any mistake or error to be expected or acceptable.
197→`;
198→
199→interface ContentBlock {
200→  type: 'text' | 'tool_use' | 'tool_result';
201→  text?: string;
202→  name?: string;
203→  input?: unknown;
204→  content?:
205→    | string
206→    | Array<{
207→        type: string;
208→        text?: string;
209→      }>;
210→}
211→
212→interface StreamMessage {
213→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
214→  subtype?: string;
215→  role?: 'assistant' | 'user';
216→  event?: {
217→    type: string;
218→    delta?: {
219→      type: string;
220→      text?: string;
221→    };
222→  };
223→  result?: string;
224→  message?: {
225→    role?: string;
226→    content?: ContentBlock[];
227→  };
228→  content?: ContentBlock[];
229→}
230→
231→interface RalphStatus {
232→  exit: boolean;
233→  task: string;
234→  remaining: number;
235→}
236→
237→function parseRalphStatus(output: string): RalphStatus | null {
238→  const marker = output.lastIndexOf('RALPH_STATUS:');
239→  if (marker === -1) return null;
240→
241→  const jsonStart = output.indexOf('{', marker);
242→  if (jsonStart === -1) return null;
243→
244→  let depth = 0;
245→  for (let i = jsonStart; i < output.length; i++) {
246→    if (output[i] === '{') depth++;
247→    if (output[i] === '}') depth--;
248→    if (depth === 0) {
249→      try {
250→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
251→        if (typeof parsed.exit === 'boolean') {
252→          return parsed as RalphStatus;
253→        }
254→      } catch {}
255→      return null;
256→    }
257→  }
258→  return null;
259→}
260→
261→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
262→
263→function killCurrentProc(): void {
264→  if (!currentProc) return;
265→  try {
266→    currentProc.kill();
267→  } catch {}
268→}
269→
270→async function checkDependencies(): Promise<void> {
271→  const result = await Bun.$`which claude`.quiet().nothrow();
272→  if (result.exitCode !== 0) {
273→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
274→    process.exit(1);
275→  }
276→
277→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
278→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
279→    process.exit(1);
280→  }
281→}
282→
283→interface IterationResult {
284→  output: string;
285→  exitCode: number;
286→  timedOut: boolean;
287→}
288→
289→async function runIteration(): Promise<IterationResult> {
290→  syslog('Executing Claude Code...');
291→
292→  const proc = Bun.spawn(
293→    [
294→      'claude',
295→      '-p',
296→      TASK_PROMPT,
297→      '--verbose',
298→      '--debug',
299→      '--dangerously-skip-permissions',
300→      '--output-format',
301→      'stream-json',
302→      '--include-partial-messages',
303→      '--model=opus',
304→    ],
305→    {
306→      cwd: process.cwd(),
307→      env: process.env,
308→      stdout: 'pipe',
309→      stderr: 'inherit',
310→    },
311→  );
312→
313→  currentProc = proc;
314→
315→  const chunks: string[] = [];
316→  let timedOut = false;
317→  const decoder = new TextDecoder();
318→  let buffer = '';
319→  let blockHasContent = false;
320→
321→  const timeoutId = setTimeout(() => {
322→    timedOut = true;
323→    syslog('Iteration timeout reached. Killing process...', 'yellow');
324→    killCurrentProc();
325→  }, CONFIG.iterationTimeout);
326→
327→  const reader = proc.stdout.getReader();
328→
329→  try {
330→    while (true) {
331→      const { done, value } = await reader.read();
332→      if (done) break;
333→
334→      buffer += decoder.decode(value, { stream: true });
335→
336→      const lines = buffer.split('\n');
337→      buffer = lines.pop() || '';
338→
339→      for (const line of lines) {
340→        if (!line.trim()) continue;
341→
342→        let msg: StreamMessage;
343→        try {
344→          msg = JSON.parse(line);
345→        } catch {
346→          continue;
347→        }
348→
349→        if (msg.type === 'stream_event') {
350→          const evt = msg.event;
351→          if (!evt) continue;
352→
353→          if (evt.type === 'content_block_start') {
354→            blockHasContent = false;
355→          } else if (evt.type === 'content_block_delta') {
356→            const text = evt.delta?.text;
357→            if (text) {
358→              print(text);
359→              chunks.push(text);
360→              blockHasContent = true;
361→            }
362→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
363→            print('\n');
364→            chunks.push('\n');
365→            blockHasContent = false;
366→          }
367→          continue;
368→        }
369→
370→        if (msg.type === 'assistant' || msg.type === 'message') {
371→          // Content already streamed via content_block_delta events.
372→          // Only print here as fallback if no streaming occurred.
373→          const blocks = msg.message?.content ?? msg.content;
374→          if (!Array.isArray(blocks)) continue;
375→
376→          for (const block of blocks) {
377→            if (block.type === 'text' && block.text && chunks.length === 0) {
378→              print(block.text);
379→              chunks.push(block.text);
380→              print('\n');
381→              chunks.push('\n');
382→            }
383→          }
384→          continue;
385→        }
386→
387→        if (msg.type === 'user') {
388→          const blocks = msg.message?.content ?? msg.content;
389→          if (!Array.isArray(blocks)) continue;
390→
391→          for (const block of blocks) {
392→            //
393→            // Handling tool result
394→            if (block.type === 'tool_result' && block.content) {
395→              const rawContent =
396→                typeof block.content === 'string'
397→                  ? block.content
398→                  : block.content
399→                      .map(c => c.text ?? '')
400→                      .filter(Boolean)
401→                      .join('\n');
402→
403→              if (!rawContent) continue;
404→
405→              let trimmed = rawContent.trim().slice(0, 320);
406→
407→              const toolResult =
408→                trimmed && trimmed !== rawContent
409→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
410→                  : rawContent;
411→
412→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
413→              chunks.push('\n', rawContent, '\n');
414→            }
415→          }
416→          continue;
417→        }
418→
419→        if (msg.type === 'result' && msg.result) {
420→          if (chunks.length === 0) {
421→            chunks.push(msg.result);
422→          }
423→        }
424→      }
425→    }
426→
427→    if (buffer.trim()) {
428→      try {
429→        const msg: StreamMessage = JSON.parse(buffer);
430→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
431→          chunks.push(msg.result);
432→        }
433→      } catch {}
434→    }
435→  } finally {
436→    clearTimeout(timeoutId);
437→    reader.releaseLock();
438→    currentProc = null;
439→    logBuffer.flush();
440→  }
441→
442→  const output = chunks.join('');
443→
444→  if (timedOut) {
445→    return {
446→      output,
447→      exitCode: 124,
448→      timedOut: true,
449→    };
450→  }
451→
452→  const exitCode = await proc.exited;
453→  println();
454→  return {
455→    output,
456→    exitCode,
457→    timedOut: false,
458→  };
459→}
460→
461→function printHeader(): void {
462→  println();
463→  println('==========================================', 'blue');
464→  println('   Ralph Loop - Bun.js Edition', 'blue');
465→  println('==========================================', 'blue');
466→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
467→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
468→  println(
469→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
470→  );
471→  println(
472→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
473→  );
474→  println();
475→}
476→
477→async function main(): Promise<void> {
478→  let cleanupCalled = false;
479→
480→  const cleanup = (signal: string) => {
481→    if (cleanupCalled) return;
482→    cleanupCalled = true;
483→    println();
484→    syslog(`Interrupted by ${signal}. Cleaning up...`);
485→    killCurrentProc();
486→    logBuffer.dispose();
487→    process.exit(signal === 'SIGINT' ? 130 : 143);
488→  };
489→
490→  process.on('SIGINT', () => cleanup('SIGINT'));
491→  process.on('SIGTERM', () => cleanup('SIGTERM'));
492→
493→  await checkDependencies();
494→
495→  printHeader();
496→  syslog('Starting automated task loop...');
497→
498→  let consecutiveFailures = 0;
499→  const MAX_CONSECUTIVE_FAILURES = 3;
500→
501→  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
502→    logBuffer.startNewFile(logFilePath(`iter-${iteration}`));
503→
504→    println();
505→    println('==========================================', 'green');
506→    syslog(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
507→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
508→    println('==========================================', 'green');
509→    println();
510→
511→    const { output, exitCode, timedOut } = await runIteration();
512→
513→    if (exitCode === 0) {
514→      syslog('Claude Code completed successfully', 'green');
515→      consecutiveFailures = 0;
516→    } else if (timedOut) {
517→      syslog('Iteration timed out — progress may persist in progress.txt', 'yellow');
518→    } else {
519→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
520→      consecutiveFailures++;
521→    }
522→
523→    if (consecutiveFailures >= MAX_CONSECUTIVE_FAILURES) {
524→      println();
525→      println('==========================================', 'red');
526→      syslog(
527→        `${MAX_CONSECUTIVE_FAILURES} consecutive failures — aborting loop`,
528→        'red',
529→      );
530→      println('==========================================', 'red');
531→      logBuffer.renameFile(logFilePath('fatal-consecutive-failures'));
532→      logBuffer.dispose();
533→      process.exit(1);
534→    }
535→
536→    const status = parseRalphStatus(output);
537→    const taskSlug = status ? slugify(status.task) : timedOut ? 'timeout' : 'no-status';
538→    logBuffer.renameFile(logFilePath(taskSlug));
539→
540→    if (status?.exit) {
541→      println();
542→      println('==========================================', 'green');
543→      syslog('ALL TASKS COMPLETED!', 'green');
544→      syslog(`Final task:      ${status.task}`, 'green');
545→      syslog(`Remaining:       ${status.remaining}`, 'green');
546→      syslog(`Total iterations: ${iteration}`, 'green');
547→      println('==========================================', 'green');
548→      logBuffer.dispose();
549→      process.exit(0);
550→    }
551→
552→    if (status) {
553→      syslog(
554→        `Task done: "${status.task}" — ${status.remaining} remaining`,
555→        'blue',
556→      );
557→    } else if (!timedOut && exitCode === 0) {
558→      syslog(
559→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
560→        'yellow',
561→      );
562→    }
563→
564→    if (iteration < CONFIG.maxIterations) {
565→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
566→      println();
567→      syslog(`Waiting ${delaySec}s before next iteration...`);
568→      await Bun.sleep(CONFIG.delayBetweenIterations);
569→    }
570→  }
571→
572→  println();
573→  println('==========================================', 'red');
574→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
575→  syslog('Loop stopped — tasks may still be pending', 'red');
576→  println('==========================================', 'red');
577→  logBuffer.dispose();
578→  process.exit(1);
579→}
580→
581→main();
